spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var stage = 1;
    if (progress >= 0.25 && progress < 0.50) stage = 2;
    else if (progress >= 0.50 && progress < 0.75) stage = 3;
    else if (progress >= 0.75) stage = 4;

    var midY = H / 2 - 20;
    var midX = W / 2;
    var step = (W - 40) / 10; // spacing between numbers

    // Draw main axis line
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(20, midY);
    ctx.lineTo(W - 20, midY);
    ctx.stroke();

    // Draw arrows at ends
    ctx.fillStyle = '#4B5563';
    ctx.beginPath();
    ctx.moveTo(15, midY);
    ctx.lineTo(25, midY - 5);
    ctx.lineTo(25, midY + 5);
    ctx.closePath();
    ctx.fill();

    ctx.beginPath();
    ctx.moveTo(W - 15, midY);
    ctx.lineTo(W - 25, midY - 5);
    ctx.lineTo(W - 25, midY + 5);
    ctx.closePath();
    ctx.fill();

    // Draw tick marks and numbers (-5 to 5)
    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';
    ctx.font = '12px monospace';

    for (var i = -5; i <= 5; i++) {
      var tx = midX + i * step;

      // Tick mark
      ctx.strokeStyle = '#4B5563';
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.moveTo(tx, midY - 4);
      ctx.lineTo(tx, midY + 4);
      ctx.stroke();

      // Highlight colors according to stage
      if (stage === 1 && i > 0) {
        ctx.fillStyle = '#60A5FA'; // Highlight positive
      } else if (stage === 2 && i < 0) {
        ctx.fillStyle = '#EF4444'; // Highlight negative
      } else if (stage === 3 && i === 0) {
        ctx.fillStyle = '#34D399'; // Highlight zero
      } else if (stage === 4 && (i === -4 || i === -1)) {
        ctx.fillStyle = i === -1 ? '#34D399' : '#EF4444'; // Highlight comparison points
      } else {
        ctx.fillStyle = '#9CA3AF'; // Standard gray
      }

      ctx.fillText(i.toString(), tx, midY + 8);
    }

    // Stage overlays
    if (stage === 1) {
      // Positive numbers highlighted on axis
      ctx.strokeStyle = 'rgba(96, 165, 250, 0.4)';
      ctx.lineWidth = 8;
      ctx.beginPath();
      ctx.moveTo(midX + 2, midY);
      ctx.lineTo(W - 30, midY);
      ctx.stroke();
    } else if (stage === 2) {
      // Negative numbers highlighted on axis
      ctx.strokeStyle = 'rgba(239, 68, 68, 0.4)';
      ctx.lineWidth = 8;
      ctx.beginPath();
      ctx.moveTo(midX - 2, midY);
      ctx.lineTo(30, midY);
      ctx.stroke();
    } else if (stage === 3) {
      // Zero highlighted
      ctx.strokeStyle = '#34D399';
      ctx.fillStyle = 'rgba(52, 211, 153, 0.3)';
      ctx.beginPath();
      ctx.arc(midX, midY, 12, 0, Math.PI * 2);
      ctx.fill();
      ctx.stroke();
    } else if (stage === 4) {
      // Draw comparison marker rings
      var x_4 = midX - 4 * step;
      var x_1 = midX - 1 * step;

      ctx.strokeStyle = '#EF4444';
      ctx.beginPath();
      ctx.arc(x_4, midY, 6, 0, Math.PI * 2);
      ctx.stroke();

      ctx.strokeStyle = '#34D399';
      ctx.beginPath();
      ctx.arc(x_1, midY, 6, 0, Math.PI * 2);
      ctx.stroke();

      // Draw comparison curve
      ctx.strokeStyle = '#FBBF24';
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.arc((x_4 + x_1) / 2, midY - 2, (x_1 - x_4) / 2, Math.PI, 0);
      ctx.stroke();

      // Arrow tip pointing right (towards -1)
      ctx.fillStyle = '#FBBF24';
      ctx.beginPath();
      ctx.moveTo(x_1 - 2, midY - 5);
      ctx.lineTo(x_1 + 3, midY - 2);
      ctx.lineTo(x_1 - 2, midY + 1);
      ctx.fill();
    }

    // Bottom text explanations
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.fillStyle = '#F3F4F6';

    if (stage === 1) {
      ctx.fillText('Positive Integers', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Numbers strictly greater than zero, lying to the right of zero.', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#F87171';
      ctx.fillText('Negative Integers', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Numbers strictly less than zero, lying to the left of zero.', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillStyle = '#34D399';
      ctx.fillText('Zero: Neutral Center', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Zero is a whole number, but it is neither positive nor negative.', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#FBBF24';
      ctx.fillText('Comparing Negatives: -1 > -4', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('-1 is warmer than -4 and lies further to the right, so it is larger.', W / 2, H - 22);
    }
  }
};
